 # This class is part of an EXPERIMENTAL API.
class VoltAPI(object):
    """---------------------------------------------------------------------------
    Service
    ---------------------------------------------------------------------------

    VoltAPI: the Voltnir external RPC surface.

    Auth is carried as gRPC metadata `authorization: Bearer <api_key>`. The
    server hashes the token (SHA-256) and looks it up against the in-memory
    user cache, identically to the REST middleware. Permission errors map to
    PERMISSION_DENIED; missing / invalid tokens map to UNAUTHENTICATED.

    Beyond the per-RPC permissions noted below, `bypass_member_check` lets a
    caller tag orders with any virtual member without an explicit assignment
    (checked inside SubmitOrder's member validation, not at the RPC gate).
    """

